def parse_nested_parens(paren_string: str) -> List[int]:
    depths = []
    for group in paren_string.split():
        max_depth = 0
        current = 0
        for ch in group:
            if ch == '(':
                current += 1
                if current > max_depth:
                    max_depth = current
            elif ch == ')':
                current -= 1
        depths.append(max_depth)
    return depths

