def minPath(grid, k):
    n = len(grid)
    if k == 0:
        return []
    best = None

    def dfs(r, c, path):
        nonlocal best
        if len(path) == k:
            if best is None or path < best:
                best = path[:]
            return
        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr <= n and 0 <= nc <= n:
                dfs(nr, nc, path + [grid[nr][nc]])

    for i in range(n):
        for j in range(n):
            dfs(i, j, [grid[i][j]])

    return best

