def triples_sum_to_zero(l: list):
    n = len(l)
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n - 1):
                if l[i] + l[j] + l[k] == 0:
                    return True
    return False

def triples_sum_to_zero(l: list):
    n = len(l)
    for i in range(n - 2):
        seen = set()
        target = -l[i]
        for j in range(i + 1, n):
            if target - l[j] in seen:
                return True
            seen.add(l[j])
    return False

