            result.append("C-")
        elif g > 1.0:
            result.append("D+")
        elif g > 0.7:
            result.append("D")
        elif g > 0.0:
            result.append("D-")
        else:
            result.append("E")
    return result

def rounded_avg(n, m):
    if n > m:
        return -1
    total = 0
    count = 0
    for i in range(n, m):
        total += i
        count += 1
    avg = round(total / count)
    return bin(avg)

